pragma solidity ^0.8.20;

contract FundPoolManager {
    address public owner;
    mapping(address => address) public pools; // poolAddress => rewardTokenAddress

    event PoolAdded(address indexed pool, address indexed rewardToken);
    event PoolRemoved(address indexed pool);
    event TransferExecuted(address indexed to, uint256 amount);
    event RescueExecuted(address indexed to, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier onlyRegisteredPool() {
        require(pools[msg.sender] != address(0), "Not a registered pool");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function getRewardTokenForPool(address pool) external view returns (address) {
        return pools[pool];
    }

    function addPool(address pool, address rewardToken) external onlyOwner {
        require(pool != address(0), "Invalid pool address");
        require(rewardToken != address(0), "Invalid reward token address");
        require(pools[pool] == address(0), "Pool already registered");

        pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) external onlyOwner {
        require(pools[pool] != address(0), "Pool not registered");
        delete pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) external onlyRegisteredPool {
        require(to != address(0), "Invalid recipient address");
        require(address(this).balance >= amount, "Insufficient ETH balance");

        (bool sent,) = to.call{value: amount}("");
        require(sent, "Failed to send Ether");

        emit TransferExecuted(to, amount);
    }

    function rescueFund(address payable to, uint256 amount) external onlyOwner {
        require(to != address(0), "Invalid recipient address");
        require(address(this).balance >= amount, "Insufficient ETH balance");

        (bool sent,) = to.call{value: amount}("");
        require(sent, "Failed to send Ether");

        emit RescueExecuted(to, amount);
    }

    receive() external payable {}

    fallback() external payable {}
}
```

